#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int X, Y; scanf("%d %d", &X, &Y);
        int costDouble = 3 * X;
        int costTriple = 2 * Y;
        int ans = costDouble < costTriple ? costDouble : costTriple;
        printf("%d\n", ans);
    }
    return 0;
}

